import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Login from './pages/Login';
import Register from './pages/Register';
import InterviewerAvailability from './pages/interviewer/InterviewerAvailability';

function App() {
  return (
    <Router>
      <div className="min-h-screen bg-gray-50">
        <Navbar />
        <Routes>
          <Route path="/" element={
            <div className="flex flex-col items-center justify-center mt-20">
              <h1 className="text-4xl font-extrabold text-gray-900">Welcome to Mock Interview Platform</h1>
              <p className="mt-4 text-gray-600 text-lg">Master your technical interviews with industry professionals.</p>
            </div>
          } />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/interviewer/availability" element={<InterviewerAvailability />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
